features.snippet:
task t(input wire [7:0] c, input wire d);
  // d is 1-bit by declaration; passing unsized 0 should not widen d
  logic [8:0] result;
  result = { c, d };
endtask
always @* t(a, 0);

task t(input wire [7:0] c, input wire d);
  output reg [8:0] b;
  b = { c, d };  // must be 9 bits: b[8:1]=c, b[0]=d
endtask

// formal port: input wire d (1-bit)
// actual arg:  0 (32-bit unsized)
// expected: d is 1'b0 inside the task, not 32'b0
task t(input wire d);
  logic [1:0] r;
  r = { 1'b1, d };
endtask
always @* t(0);
